// GLSL 450 函数定义
vec4 transformVertex(vec3 pos, mat4 mvp) {
    return mvp * vec4(pos, 1.0);
}

void main() {
    gl_Position = transformVertex(a_position, u_MVP);
}

// WGSL 函数定义
fn transformVertex(pos: vec3<f32>, mvp: mat4x4<f32>) -> vec4<f32> {
    return mvp * vec4<f32>(pos, 1.0);
}

@vertex
fn main(@location(0) a_position: vec3<f32>) -> @builtin(position) vec4<f32> {
    return transformVertex(a_position, u_MVP);
}

const PI: f32 = 3.14159265358979;
const MAX_LIGHTS: i32 = 8;
const UP: vec3<f32> = vec3<f32>(0.0, 1.0, 0.0);

override resolution: f32 = 1.0;   // 默认值
override useTexture: bool = true;   // 默认启用纹理

@fragment
fn main() -> @location(0) vec4<f32> {
    if (useTexture) {
        return textureSample(myTexture, mySampler, uv) * resolution;
    }
    return vec4<f32>(1.0, 0.0, 0.0, 1.0);
}

@fragment
fn main(@location(0) uv: vec2<f32>) -> @location(0) vec4<f32> {
    let texCoord = uv * 2.0 - 1.0;        // 运行时计算，不可修改
    let color = textureSample(tex, s, texCoord);
    let luminance = dot(color.rgb, vec3<f32>(0.299, 0.587, 0.114));
    return vec4<f32>(luminance, luminance, luminance, color.a);
}

// 1. 结构体声明
struct Uniforms {
    mvp: mat4x4<f32>,
    color: vec4<f32>,
};

struct VertexInput {
    @location(0) position: vec3<f32>,
    @location(1) uv: vec2<f32>,
};

struct VertexOutput {
    @builtin(position) position: vec4<f32>,
    @location(0) uv: vec2<f32>,
    @location(1) color: vec4<f32>,
};

// 2. 绑定资源
@group(0) @binding(0) var<uniform> uniforms: Uniforms;
@group(0) @binding(1) var myTexture: texture_2d<f32>;
@group(0) @binding(2) var mySampler: sampler;

// 3. 顶点入口
@vertex
fn vs_main(input: VertexInput) -> VertexOutput {
    var output: VertexOutput;
    output.position = uniforms.mvp * vec4<f32>(input.position, 1.0);
    output.uv = input.uv;
    output.color = uniforms.color;
    return output;
}

// 4. 片段入口
@fragment
fn fs_main(input: VertexOutput) -> @location(0) vec4<f32> {
    let texColor = textureSample(myTexture, mySampler, input.uv);
    return texColor * input.color;
}

